item.description:
 &lt;h2 id=&#34;项目介绍&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#项目介绍&#34;&gt;#&lt;/a&gt; &lt;strong&gt;项目介绍&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;Masuit.Tools (码数吐司库) 是一个全龄段友好的 C#/.NET 万能工具库，不管你是菜鸟新手还是骨灰级玩家都能轻松上手。&lt;/p&gt;
&lt;h2 id=&#34;包含功能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#包含功能&#34;&gt;#&lt;/a&gt; &lt;strong&gt;包含功能&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;这个库包含一些常用的操作类，大都是静态类，加密解密，反射操作，树结构，文件探测，权重随机筛选算法，分布式短 id，表达式树，linq 扩展，文件压缩，多线程下载，硬件信息，字符串扩展方法，日期时间扩展操作，中国农历，大文件拷贝，图像裁剪，验证码，断点续传，集合扩展、Excel 导出等常用封装。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;诸多功能集一身，代码量不到 2MB！&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.gitmirror.com/wangbin-blog/pic-resources/main/2024/09/640%3Fwx_fmt%3Dpng%26from%3Dappmsg%26tp%3Dwebp%26wxfrom%3D5%26wx_lazy%3D1%26wx_co%3D1&#34; alt=&#34;图片&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;建议开发环境&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#建议开发环境&#34;&gt;#&lt;/a&gt; &lt;strong&gt;建议开发环境&lt;/strong&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;操作系统：Windows 11 23H2 及以上版本.&lt;/li&gt;
&lt;li&gt;开发工具：VisualStudio2022 v17.8 及以上版本.&lt;/li&gt;
&lt;li&gt;SDK：.Net Core 2.1.0 及以上所有版本.&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;字符串检查&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#字符串检查&#34;&gt;#&lt;/a&gt; &lt;strong&gt;字符串检查&lt;/strong&gt;&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;检验字符串是否是 Email、手机号、URL、IP 地址、身份证号等&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code class=&#34;language-c#&#34;&gt;var (isMatch, match) = &amp;quot;337845818@qq.com&amp;quot;.MatchEmail(); // 可在appsetting.json中添加EmailDomainWhiteList和EmailDomainBlockList配置邮箱域名黑白名单，逗号分隔，如&amp;quot;EmailDomainBlockList&amp;quot;: &amp;quot;^\\w&amp;#123;1,5&amp;#125;@qq.com,^\\w&amp;#123;1,5&amp;#125;@163.com,^\\w&amp;#123;1,5&amp;#125;@gmail.com,^\\w&amp;#123;1,5&amp;#125;@outlook.com&amp;quot;,
bool isInetAddress = &amp;quot;114.114.114.114&amp;quot;.MatchInetAddress(); // 匹配IP地址
bool isUrl = &amp;quot;http://masuit.org/20/history&amp;quot;.MatchUrl(); // 匹配url
bool isPhoneNumber = &amp;quot;15205201520&amp;quot;.MatchPhoneNumber(); // 匹配手机号
bool isLandline = &amp;quot;01088888888&amp;quot;.MatchLandline(); // 匹配座机号
bool isIdentifyCard = &amp;quot;312000199502230660&amp;quot;.MatchIdentifyCard();// 校验中国大陆身份证号
bool isCNPatentNumber = &amp;quot;200410018477.9&amp;quot;.MatchCNPatentNumber(); // 校验中国专利申请号或专利号，是否带校验位，校验位前是否带“.”，都可以校验，待校验的号码前不要带CN、ZL字样的前缀
bool isUSCC = &amp;quot;200410018477.9&amp;quot;.MatchUSCC(); // 校验企业统一社会信用代码
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;硬件监测&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#硬件监测&#34;&gt;#&lt;/a&gt; &lt;strong&gt;硬件监测&lt;/strong&gt;&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;硬件监测 (需要管理员权限，仅支持 Windows，部分函数仅支持物理机模式)!&lt;/p&gt;
&lt;/blockquote&gt;
&lt;pre&gt;&lt;code class=&#34;language-c#&#34;&gt;float load = SystemInfo.CpuLoad;// 获取CPU占用率
long physicalMemory = SystemInfo.PhysicalMemory;// 获取物理内存总数
long memoryAvailable = SystemInfo.MemoryAvailable;// 获取物理内存可用率
double freePhysicalMemory = SystemInfo.GetFreePhysicalMemory();// 获取可用物理内存
double temperature = SystemInfo.GetCPUTemperature();// 获取CPU温度
int cpuCount = SystemInfo.GetCpuCount();// 获取CPU核心数
var ipAddress = SystemInfo.GetLocalIPs();// 获取本机所有IP地址
string localUsedIp = SystemInfo.GetLocalUsedIP();// 获取本机当前正在使用的IP地址
IList&amp;lt;string&amp;gt; macAddress = SystemInfo.GetMacAddress();// 获取本机所有网卡mac地址
string osVersion = Windows.GetOsVersion();// 获取操作系统版本
RamInfo ramInfo = SystemInfo.GetRamInfo();// 获取内存信息
var cpuSN=SystemInfo.GetCpuInfo()[0].SerialNumber; // CPU序列号
var driveSN=SystemInfo.GetDiskInfo()[0].SerialNumber; // 硬盘序列号

// 快速方法
var cpuInfos = CpuInfo.Locals; // 快速获取CPU的信息
var ramInfo = RamInfo.Local; // 快速获取内存的信息
var diskInfos = DiskInfo.Locals; // 快速获取硬盘的信息
var biosInfo = BiosInfo.Local; // 快速获取主板的信息
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;linqextension&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#linqextension&#34;&gt;#&lt;/a&gt; &lt;strong&gt;LinqExtension&lt;/strong&gt;&lt;/h2&gt;
&lt;pre&gt;&lt;code class=&#34;language-c#&#34;&gt;using System;
using System.Collections.Generic;
using System.Linq.Expressions;

namespace Masuit.Tools.Linq;

/// &amp;lt;summary&amp;gt;
/// LINQ扩展方法
/// &amp;lt;/summary&amp;gt;
public static class LinqExtension
&amp;#123;
    /// &amp;lt;summary&amp;gt;
    /// 与连接
    /// &amp;lt;/summary&amp;gt;
    /// &amp;lt;typeparam name=&amp;quot;T&amp;quot;&amp;gt;类型&amp;lt;/typeparam&amp;gt;
    /// &amp;lt;param name=&amp;quot;left&amp;quot;&amp;gt;左条件&amp;lt;/param&amp;gt;
    /// &amp;lt;param name=&amp;quot;right&amp;quot;&amp;gt;右条件&amp;lt;/param&amp;gt;
    /// &amp;lt;returns&amp;gt;新表达式&amp;lt;/returns&amp;gt;
    public static Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; And&amp;lt;T&amp;gt;(this Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; left, Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; right)
    &amp;#123;
        return CombineLambdas(left, right, ExpressionType.AndAlso);
    &amp;#125;

    /// &amp;lt;summary&amp;gt;
    /// 与连接
    /// &amp;lt;/summary&amp;gt;
    /// &amp;lt;typeparam name=&amp;quot;T&amp;quot;&amp;gt;类型&amp;lt;/typeparam&amp;gt;
    /// &amp;lt;param name=&amp;quot;left&amp;quot;&amp;gt;左条件&amp;lt;/param&amp;gt;
    /// &amp;lt;param name=&amp;quot;condition&amp;quot;&amp;gt;符合什么条件&amp;lt;/param&amp;gt;
    /// &amp;lt;param name=&amp;quot;right&amp;quot;&amp;gt;右条件&amp;lt;/param&amp;gt;
    /// &amp;lt;returns&amp;gt;新表达式&amp;lt;/returns&amp;gt;
    public static Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; AndIf&amp;lt;T&amp;gt;(this Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; left, bool condition, Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; right)
    &amp;#123;
        return condition ? CombineLambdas(left, right, ExpressionType.AndAlso) : left;
    &amp;#125;

    /// &amp;lt;summary&amp;gt;
    /// 与连接
    /// &amp;lt;/summary&amp;gt;
    /// &amp;lt;typeparam name=&amp;quot;T&amp;quot;&amp;gt;类型&amp;lt;/typeparam&amp;gt;
    /// &amp;lt;param name=&amp;quot;left&amp;quot;&amp;gt;左条件&amp;lt;/param&amp;gt;
    /// &amp;lt;param name=&amp;quot;condition&amp;quot;&amp;gt;符合什么条件&amp;lt;/param&amp;gt;
    /// &amp;lt;param name=&amp;quot;right&amp;quot;&amp;gt;右条件&amp;lt;/param&amp;gt;
    /// &amp;lt;returns&amp;gt;新表达式&amp;lt;/returns&amp;gt;
    public static Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; AndIf&amp;lt;T&amp;gt;(this Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; left, Func&amp;lt;bool&amp;gt; condition, Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; right)
    &amp;#123;
        return condition() ? CombineLambdas(left, right, ExpressionType.AndAlso) : left;
    &amp;#125;

    /// &amp;lt;summary&amp;gt;
    /// 或连接
    /// &amp;lt;/summary&amp;gt;
    /// &amp;lt;typeparam name=&amp;quot;T&amp;quot;&amp;gt;类型&amp;lt;/typeparam&amp;gt;
    /// &amp;lt;param name=&amp;quot;left&amp;quot;&amp;gt;左条件&amp;lt;/param&amp;gt;
    /// &amp;lt;param name=&amp;quot;right&amp;quot;&amp;gt;右条件&amp;lt;/param&amp;gt;
    /// &amp;lt;returns&amp;gt;新表达式&amp;lt;/returns&amp;gt;
    public static Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; Or&amp;lt;T&amp;gt;(this Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; left, Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; right)
    &amp;#123;
        return CombineLambdas(left, right, ExpressionType.OrElse);
    &amp;#125;

    /// &amp;lt;summary&amp;gt;
    /// 或连接
    /// &amp;lt;/summary&amp;gt;
    /// &amp;lt;typeparam name=&amp;quot;T&amp;quot;&amp;gt;类型&amp;lt;/typeparam&amp;gt;
    /// &amp;lt;param name=&amp;quot;left&amp;quot;&amp;gt;左条件&amp;lt;/param&amp;gt;
    /// &amp;lt;param name=&amp;quot;condition&amp;quot;&amp;gt;符合什么条件&amp;lt;/param&amp;gt;
    /// &amp;lt;param name=&amp;quot;right&amp;quot;&amp;gt;右条件&amp;lt;/param&amp;gt;
    /// &amp;lt;returns&amp;gt;新表达式&amp;lt;/returns&amp;gt;
    public static Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; OrIf&amp;lt;T&amp;gt;(this Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; left, bool condition, Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; right)
    &amp;#123;
        return condition ? CombineLambdas(left, right, ExpressionType.OrElse) : left;
    &amp;#125;

    /// &amp;lt;summary&amp;gt;
    /// 或连接
    /// &amp;lt;/summary&amp;gt;
    /// &amp;lt;typeparam name=&amp;quot;T&amp;quot;&amp;gt;类型&amp;lt;/typeparam&amp;gt;
    /// &amp;lt;param name=&amp;quot;left&amp;quot;&amp;gt;左条件&amp;lt;/param&amp;gt;
    /// &amp;lt;param name=&amp;quot;condition&amp;quot;&amp;gt;符合什么条件&amp;lt;/param&amp;gt;
    /// &amp;lt;param name=&amp;quot;right&amp;quot;&amp;gt;右条件&amp;lt;/param&amp;gt;
    /// &amp;lt;returns&amp;gt;新表达式&amp;lt;/returns&amp;gt;
    public static Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; OrIf&amp;lt;T&amp;gt;(this Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; left, Func&amp;lt;bool&amp;gt; condition, Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; right)
    &amp;#123;
        return condition() ? CombineLambdas(left, right, ExpressionType.OrElse) : left;
    &amp;#125;

    private static Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; CombineLambdas&amp;lt;T&amp;gt;(this Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; left, Expression&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt; right, ExpressionType expressionType)
    &amp;#123;
        var visitor = new SubstituteParameterVisitor
        &amp;#123;
            Sub =
            &amp;#123;
                [right.Parameters[0]] = left.Parameters[0]
            &amp;#125;
        &amp;#125;;

        Expression body = Expression.MakeBinary(expressionType, left.Body, visitor.Visit(right.Body));
        return Expression.Lambda&amp;lt;Func&amp;lt;T, bool&amp;gt;&amp;gt;(body, left.Parameters[0]);
    &amp;#125;
&amp;#125;

internal class SubstituteParameterVisitor : ExpressionVisitor
&amp;#123;
    public Dictionary&amp;lt;Expression, Expression&amp;gt; Sub = new();

    protected override Expression VisitParameter(ParameterExpression node)
    &amp;#123;
        return Sub.TryGetValue(node, out var newValue) ? newValue : node;
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;开源地址&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#开源地址&#34;&gt;#&lt;/a&gt; &lt;strong&gt;开源地址&lt;/strong&gt;&lt;/h2&gt;
&lt;p&gt;&lt;a href=&#34;https://github.com/ldqk/Masuit.Tools&#34;&gt;https://github.com/ldqk/Masuit.Tools&lt;/a&gt;&lt;/p&gt;

 &lt;h3 id=&#34;先看效果-️&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#先看效果-️&#34;&gt;#&lt;/a&gt; 先看效果 👁️&lt;/h3&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.gitmirror.com/wangbin-blog/pic-resources/main/2024/08/1499be202c9c43f7b3729502c31411f6&#34; alt=&#34;图片&#34; /&gt;&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.gitmirror.com/wangbin-blog/pic-resources/main/2024/08/89753498cef341ceb3cbec1e6d4e3f13&#34; alt=&#34;图片&#34; /&gt;&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;https://raw.gitmirror.com/wangbin-blog/pic-resources/main/2024/08/5a1f6cf1302d4d2b8f8522728ba5da26&#34; alt=&#34;图片&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;页面源码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#页面源码&#34;&gt;#&lt;/a&gt; 页面源码🦅&lt;/h3&gt;
&lt;h4 id=&#34;紫色登录界面图一&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#紫色登录界面图一&#34;&gt;#&lt;/a&gt; 紫色登录界面（图一）：&lt;/h4&gt;
