&lt;td style=&#34;text-align:center&#34;&gt;&lt;a href=&#34;https://github.com/umbraco/Umbraco-CMS&#34;&gt;https://github.com/umbraco/Umbraco-CMS&lt;/a&gt;&lt;/td&gt;
&lt;/tr&gt;
