&lt;td style=&#34;text-align:center&#34;&gt;&lt;a href=&#34;https://github.com/FreakyAli/Maui.FreakyEffects&#34;&gt;https://github.com/FreakyAli/Maui.FreakyEffects&lt;/a&gt;&lt;/td&gt;
